class Urun:
    def __init__(self, fiyat):
        self.fiyat = fiyat

    def fiyat_artir(self, oran):
        self.fiyat *= 1 + oran

urun = Urun(100)
urun.fiyat_artir(0.20)
print(urun.fiyat)

